WITH src AS (SELECT VERSION() AS db_version, CAST((SELECT CURRENT_SETTING('server_version_num')) AS INT) AS server_version_num, PG_IS_IN_RECOVERY() AS is_replica, PG_POSTMASTER_START_TIME() AS server_start_time, INET_SERVER_ADDR() AS server_ip, CASE WHEN VERSION() ~* 'RDS' THEN 'AWS_RDS' WHEN VERSION() ~* 'Aurora' THEN 'AWS_AURORA' WHEN VERSION() ~* 'Cloud SQL' THEN 'GCP_CLOUDSQL' WHEN VERSION() ~* 'AlloyDB' THEN 'GCP_ALLOYDB' WHEN VERSION() ~* 'Redshift' THEN 'AWS_REDSHIFT' ELSE 'NATIVE_POSTGRESQL' END AS cloud_provider) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.db_version, src.server_version_num, src.is_replica, src.server_start_time, src.server_ip, src.cloud_provider FROM src